import{_ as t,o as a,c as r,ao as n}from"./chunks/framework.BwTKejc4.js";const p=JSON.parse('{"title":"Deprecated marker internals","description":"","frontmatter":{},"headers":[],"relativePath":"reference/deprecated-marker-internals.md","filePath":"reference/deprecated-marker-internals.md","lastUpdated":null}'),s={name:"reference/deprecated-marker-internals.md"};function d(o,e,i,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="Deprecated-marker-internals" tabindex="-1">Deprecated marker internals <a class="header-anchor" href="#Deprecated-marker-internals" aria-label="Permalink to &quot;Deprecated marker internals {#Deprecated-marker-internals}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Reference (parity)</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/reference/index.html" target="_blank" rel="noreferrer">Deprecated marker internals</a> (2 in drmTMB). These are <strong>deprecated drmTMB names</strong>; DRM.jl ships the modern replacement and documents the mapping here so users porting R code know what to write instead. The deprecated names are <em>not</em> part of DRM.jl&#39;s public API.</p></div><h2 id="Deprecation-map" tabindex="-1">Deprecation map <a class="header-anchor" href="#Deprecation-map" aria-label="Permalink to &quot;Deprecation map {#Deprecation-map}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">drmTMB (deprecated)</th><th style="text-align:right;">Use instead in DRM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>meta_known_V(V)</code></td><td style="text-align:right;"><code>meta_V(v)</code></td><td style="text-align:right;">Meta-analysis with known sampling (co)variances. The modern spelling is <code>meta_V</code>, attached to a <code>Gaussian()</code> model: <code>drm(bf(y ~ meta_V(v)), Gaussian(); data = …)</code>.</td></tr><tr><td style="text-align:right;"><code>gr(…)</code></td><td style="text-align:right;">(no equivalent needed)</td><td style="text-align:right;">A drmTMB internal gradient helper; DRM.jl computes gradients via ForwardDiff / the exact implicit-function path, so there is no user-facing equivalent.</td></tr></tbody></table><h2 id="Why-DRM.jl-doesn&#39;t-carry-the-old-names" tabindex="-1">Why DRM.jl doesn&#39;t carry the old names <a class="header-anchor" href="#Why-DRM.jl-doesn&#39;t-carry-the-old-names" aria-label="Permalink to &quot;Why DRM.jl doesn&#39;t carry the old names {#Why-DRM.jl-doesn&#39;t-carry-the-old-names}&quot;">​</a></h2><p>drmTMB keeps <code>meta_known_V</code> / <code>gr</code> only as deprecated shims for backward compatibility with older R scripts. DRM.jl is a fresh Julia API, so it exposes <strong>only the current names</strong> — there is no legacy surface to preserve. If you are translating an R script that calls <code>meta_known_V</code>, replace it with <code>meta_V</code>; the arguments (the known sampling variances) carry over directly.</p><p>For the meta-analysis workflow itself, see the meta-analysis tutorial and the <code>meta_V</code> entry in the structured-effect markers reference.</p>',7)])])}const g=t(s,[["render",d]]);export{p as __pageData,g as default};
